INSERT INTO public.photos VALUES (22301, 'Campo Sepulcro 1967', 'Archivo Municipal. Gerardo Sancho Ramo. Noviembre 1967. Imagen del mar de vâ”śÂˇas de la estaciâ”śâ”‚n de tren Campo Sepulcro, a puento de pasar un convoy tirado por una nueva locomotora diesel. A la derecha, las vaporosas en su depâ”śâ”‚sito, con un futuro bastante incierto.', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65008400, -0.89472000, '0101000020E6100000C47762D68BA1ECBF91D3D7F335D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15559127050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15559127050.webp', 'https://www.flickr.com/photos/zaragozaantigua/15559127050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22786, 'Calle de Santander 1976', 'Imagen capturada en el arranque de la calle de Santander desde la de Escoriaza y Fabro. A la derecha, donde estuviera ubicada la antigua estaciâ”śâ”‚n del ferrocarril de vâ”śÂˇa estrecha de Cariâ”śâ–’ena-Zaragoza, la manzana delimitada por las calles de Asturias y de Cariâ”śâ–’ena, con los bloques finalizados de los nâ”śâ•‘meros 4 y 6, y el resto en construcciâ”śâ”‚n, o en trâ”śĂ­nsito hacia el derribo, como el chaflâ”śĂ­n de primer plano a la derecha. Al fondo, la moderna plaza de Roma. La ancha calzada para circulaciâ”śâ”‚n motorizada determina el espacio resultante y algunos vehâ”śÂˇculos, incluso, ocupan la acera aparcados temporalmente en la acera de la izquierda. A la derecha, una soleada cabina telefâ”śâ”‚nica. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64879300, -0.89449500, '0101000020E6100000C8EF6DFAB39FECBFD66F26A60BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38497478261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38497478261.webp', 'https://www.flickr.com/photos/zaragozaantigua/38497478261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22843, 'Calle Anselmo Clavâ”śÂ® 1989', 'Demoliciâ”śâ”‚n completa de un edificio de viviendas de 6 plantas, de estructura mixta hormigâ”śâ”‚n y madera, en el chaflâ”śĂ­n de la calle Anselmo Clavâ”śÂ® con la calle Madre Sacramento.', 1989, 1989, 1989, 'Anos 80', 'DELICIAS', 41.65077300, -0.89351800, '0101000020E6100000FE648C0FB397ECBF560F98874CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15108149056.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15108149056.webp', 'https://www.flickr.com/photos/zaragozaantigua/15108149056/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22984, 'El Portillo aâ”śâ–’os 90', 'Vista aâ”śÂ®rea de la zona de Zaragoza alrededor de la estaciâ”śâ”‚n del Portillo. Fuente: viajesferroviarios.blogspot.com.es/2015/01/la-revolucion-...', 1990, 1990, 1999, 'Anos 90', 'DELICIAS', 41.65077600, -0.89416200, '0101000020E6100000336E6AA0F99CECBFC782C2A04CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19259886222.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19259886222.webp', 'https://www.flickr.com/photos/zaragozaantigua/19259886222/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23155, 'Calle Asturias 2009', 'Foto: Juan Carlos Arcos. Construcciâ”śâ”‚n de la Escuela Infantil Municipal El Andâ”śÂ®n, en la calle de San Pedro Arbuâ”śÂ®s 4. La imagen muestra la fachada recayente a la calle de Asturias. Este equipamiento pâ”śâ•‘blico del barrio de Las Delicias fue inaugurado en 2010. Fuente: Heraldo de Aragâ”śâ”‚n.', 2009, 2009, 2009, 'Siglo XXI', 'DELICIAS', 41.65019300, -0.89565600, '0101000020E6100000EAEA8EC536A9ECBF488B338639D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32352330903.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32352330903.webp', 'https://www.flickr.com/photos/zaragozaantigua/32352330903/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23184, 'El Portillo c.2000', 'El tren diurno "Râ”śÂˇo Aragâ”śâ”‚n" Madrid-Jaca parte desde la estaciâ”śâ”‚n de Zaragoza-El Portillo tras el preceptivo cambio de la locomotora elâ”śÂ®ctrica que lo traccionâ”śâ”‚ hasta aquâ”śÂˇ por la diesel 319.3 de la imagen, debido a la ausencia de catenaria desde Tardienta. Este servicio convencional desapareciâ”śâ”‚ en diciembre de 2003 como otros tantos como consecuencia de la entrada en servicio la Alta Velocidad Espaâ”śâ–’ola. Esta locomotora fue vendida a la Repâ”śâ•‘blica Argentina en 2009.', 2000, 2000, 2000, 'Siglo XXI', 'DELICIAS', 41.65083700, -0.89426900, '0101000020E6100000B4739A05DA9DECBF6D0377A04ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51046375371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51046375371.webp', 'https://www.flickr.com/photos/zaragozaantigua/51046375371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23318, 'Vista Campo Sepulcro c.1967', 'Panorama de las instalaciones de la Estaciâ”śâ”‚n de ferrocarril de Campo Sepulcro. Los edificios centrales de la Estaciâ”śâ”‚n quedan empequeâ”śâ–’ecidos ante el impresionante Depâ”śâ”‚sito de Locomotoras. Ademâ”śĂ­s, talleres, aguadas, almacenes, viviendas... A la izquierda, el enorme complejo industrial de Carde y Escoriaza. Un poco mâ”śĂ­s al fondo, el Paso a Nivel de Delicias. A la derecha, al fondo, la chimenea de Averly. La imagen ha sido tomada desde la azotea del nâ”¬â•‘ 27 de la calle Alselmo Clavâ”śÂ® (la sombra que se proyecta), por aquel entonces el â”śâ•‘nico edificio de gran altura en toda esa parte de la calle.', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65050000, -0.89364700, '0101000020E61000007364E597C198ECBF2506819543D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14787761130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14787761130.webp', 'https://www.flickr.com/photos/zaragozaantigua/14787761130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23970, 'Jardâ”śÂˇn de Invierno 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Mayo 1966. Imagen de una simpâ”śĂ­tica reuniâ”śâ”‚n-encuentro de la Delegaciâ”śâ”‚n Nacional del Frente de Juventudes (organizaciâ”śâ”‚n juvenil del franquismo) en el Parque Primo de Rivera, en el precioso Jardâ”śÂˇn de Invierno.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63172600, -0.89277800, '0101000020E610000041D3122BA391ECBF3604C765DCD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15097672174.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15097672174.webp', 'https://www.flickr.com/photos/zaragozaantigua/15097672174/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23322, 'Estaciâ”śâ”‚n de Cariâ”śâ–’ena c.1900', 'Principios Siglo XX. Colecciâ”śâ”‚n Gerardo Alcaâ”śâ–’iz. La Estaciâ”śâ”‚n de Cariâ”śâ–’ena se inaugurâ”śâ”‚ en 1887, muy cerca de la de Campo Sepulcro. En la imagen, al fondo, las traseras del edificio de la Estaciâ”śâ”‚n, cuyos andenes quedaban recayentes hacia el otro lado. En la vâ”śÂˇa, el tranvâ”śÂˇa M-3, habilitado para transporte de mercancâ”śÂˇas, desde esta Estaciâ”śâ”‚n, por la red tranviaria de la ciudad. La Estaciâ”śâ”‚n de Cariâ”śâ–’ena se ubicaba en lo que ahora es comienzo de la calle Santander. Fue clausurada en 1933, y desmantelado el tendido. El edificio de la estaciâ”śâ”‚n serâ”śÂˇa derribado a principios de los aâ”śâ–’os 50.', 1900, 1900, 1900, 'Anos 1900', 'DELICIAS', 41.64879300, -0.89449500, '0101000020E6100000C8EF6DFAB39FECBFD66F26A60BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14955731386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14955731386.webp', 'https://www.flickr.com/photos/zaragozaantigua/14955731386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23323, 'Campo Sepulcro 1966', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 1966. Imagen tomada desde la pasarela peatonal sobre el mar de vâ”śÂˇas de la Estaciâ”śâ”‚n de Campo Sepulcro, encauzado hacia la Avenida Goya. Al fondo, a la izquierda, el edificio central de la Estaciâ”śâ”‚n. A la izquierda, el depâ”śâ”‚sito de locomotoras. Escoriaza y Fabro queda a la izquierda, donde la fâ”śĂ­brica Orâ”śâ•‘s; Anselmo Clavâ”śÂ®, a la derecha.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.64917000, -0.89409800, '0101000020E61000008368AD68739CECBFACC5A70018D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15237567832.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15237567832.webp', 'https://www.flickr.com/photos/zaragozaantigua/15237567832/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23325, 'Campo Sepulcro 1912', 'Despedida de tropas coloniales en la Estaciâ”śâ”‚n Campo Sepulcro, con direcciâ”śâ”‚n al norte de â”śĂĽfrica, a pelear en la Guerra del Rif.', 1912, 1912, 1912, 'Anos 10', 'DELICIAS', 41.65103300, -0.89411400, '0101000020E6100000EFA99CF6949CECBFF2CEA10C55D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15458669657.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15458669657.webp', 'https://www.flickr.com/photos/zaragozaantigua/15458669657/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23329, 'Campo Sepulcro c.1965', 'Locomotora de vapor Compound De Glehn fabricada en Alemania en 1902, en servicio para la MZA, capturada un poco antes de llegar a la estaciâ”śâ”‚n de Campo Sepulcro. Al fondo, Talleres Mercier, en la avenida de Josâ”śÂ® Anselmo Clavâ”śÂ®. Fuente visual: Foto J.B. Snell, en image.slidesharecdn.com/', 1965, 1965, 1965, 'Anos 60', 'DELICIAS', 41.65103300, -0.89411400, '0101000020E6100000EFA99CF6949CECBFF2CEA10C55D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20524912229.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20524912229.webp', 'https://www.flickr.com/photos/zaragozaantigua/20524912229/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23333, 'Estaciâ”śâ”‚n de Cariâ”śâ–’ena 1887', '"Tren oficial de la inauguraciâ”śâ”‚n" de la nueva estaciâ”śâ”‚n del ferrocarril de Zaragoza a Cariâ”śâ–’ena, el 10 de agosto de 1887. Al fondo, el edificio central de la Estaciâ”śâ”‚n, en el entorno de Campo del Sepulcro, en una zona luego denominada "barrio de Cariâ”śâ–’ena". Esta lâ”śÂˇnea fue clausurada y desmantelada en 1933 al entrar en servicio la nueva lâ”śÂˇnea Zaragoza- Teruel-Valencia.', 1887, 1887, 1887, 'Siglo XIX', 'DELICIAS', 41.64879300, -0.89449500, '0101000020E6100000C8EF6DFAB39FECBFD66F26A60BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25190810155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25190810155.webp', 'https://www.flickr.com/photos/zaragozaantigua/25190810155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23335, 'Campo Sepulcro 1961', 'Imagen capturada desde el pretil del mar de vâ”śÂˇas ferroviarias, que hacia la izquierda se ensanchaba progresivamente hasta llegar a la estaciâ”śâ”‚n Campo Sepulcro. Al otro lado de la zanja, Anselmo Clavâ”śÂ®, y al fondo, el antiguo edificio de la Casa de Convalecientes, que desde finales de los aâ”śâ–’os cincuenta estaba ocupado por el Colegio Politâ”śÂ®cnico Nuestra Seâ”śâ–’ora del Pilar. Fuente visual: Archivo Municipal de Zaragoza', 1961, 1961, 1961, 'Anos 60', 'DELICIAS', 41.64917000, -0.89409800, '0101000020E61000008368AD68739CECBFACC5A70018D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30091576485.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30091576485.webp', 'https://www.flickr.com/photos/zaragozaantigua/30091576485/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23340, 'Campo Sepulcro 1967', 'Imagen capturada en el mar de vâ”śÂˇas de la antigua estaciâ”śâ”‚n de Campo Sepulcro, centrada en dos locomotoras vaporosas allâ”śÂˇ estacionadas, la primera, de la serie 240-4000, y la segunda, de la serie 241-4000 (ambas, numeraciâ”śâ”‚n RENFE). Al fondo, la avenida Anselmo Clavâ”śÂ®, y el reconocible edificio chaflanero con la calle Madre Sacramento, frente al cuartel de la Policâ”śÂˇa Armada. A la izquierda, remates de las viviendas militares recayentes a la calle General Mayandâ”śÂˇa y el paseo de Mâ”¬Â¬ Agustâ”śÂˇn. Fuente visual: foto Graham T.V. Stacey, en www.spanishrailway.com/', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65009400, -0.89398900, '0101000020E6100000D57ABFD18E9BECBFB5A9BA4736D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31956847385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31956847385.webp', 'https://www.flickr.com/photos/zaragozaantigua/31956847385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23345, 'Campo Sepulcro 1911', 'Imagen capturada desde el mar de vâ”śÂˇas de la estaciâ”śâ”‚n de Campo Sepulcro de la zanja, o trinchera, y vâ”śÂˇa â”śâ•‘nica del ferrocarril MZA en direcciâ”śâ”‚n a Barcelona, asâ”śÂˇ como de los nuevos pasos elevados tendidos sobre ella, siendo el de primer plano el que conducâ”śÂˇa hacia la derecha al ingreso principal a la estaciâ”śâ”‚n de ferrocarril de Cariâ”śâ–’ena, y los siguientes en el entorno del cruce de la carretera de Zaragoza a Valencia por Teruel. Fuente visual: hemerotecadigital.bne.es/', 1911, 1911, 1911, 'Anos 10', 'DELICIAS', 41.64889100, -0.89394600, '0101000020E6100000037B4CA4349BECBF99D53BDC0ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39010644140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39010644140.webp', 'https://www.flickr.com/photos/zaragozaantigua/39010644140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24172, 'Pasarela Avenida de Goya 1966', 'AYUNTAMIENTO DE ZARAGOZA/Sancho Ramo, Gerardo/Abril 1966. Desde la Estaciâ”śâ”‚n de Campo Sepulcro y hasta el Paseo de Teruel, donde terminaba la Avenida de Goya, la trinchera del ferrocarril en direcciâ”śâ”‚n a Barcelona seguâ”śÂˇa al aire, sin cubrir. Una pasarela metâ”śĂ­lica salvaba esa contingencia. Hacia la derecha, sucesivamente se abren reconocibles las calles de Santander, Tarragona-Burgos, Paseo de Teruel, y S. Antonio Marâ”śÂˇa Claret. En ese punto la Avenida de Goya comienza una peraltada curva hacia la izquierda, en la que se perfila el Corazâ”śâ”‚n de Marâ”śÂˇa (parroquia catâ”śâ”‚lica). El lado izquierdo de la Avenida estaba menos urbanizado, y hoy sâ”śâ”‚lo perdura el reciente edificio de 10 plantas que chaflanea la calle Câ”śĂ­novas. Justo a la derecha, en primer tâ”śÂ®rmino, donde arranca la calle Santander, desde 1887 y hasta 1933 estuvo activa la Estaciâ”śâ”‚n de tren de vâ”śÂˇa estrecha de Cariâ”śâ–’ena. Abandonada la lâ”śÂˇnea ese aâ”śâ–’o, con la entrada en funcionamiento de la lâ”śÂˇnea de Caminreal, su recorrido por la ciudad fue pronto urbanizado, y el edificio de la estaciâ”śâ”‚n piqueteado en 1940. La paralela calle Cariâ”śâ–’ena recuerda su existencia. En la actualidad, en este punto comienza el espacio de la Glorieta de los Zagrâ”śÂˇes, confluencia de Anselmo Clavâ”śÂ®, Escoriaza y Fabro, y Goya.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.64883300, -0.89395800, '0101000020E610000014ECBFCE4D9BECBF65C8B1F50CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14849306291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14849306291.webp', 'https://www.flickr.com/photos/zaragozaantigua/14849306291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24255, 'Calle de Pamplona 1937', 'Familiar imagen de Gustavo Freudenthal Neuhaus, fotâ”śâ”‚grafo retirado y excâ”śâ”‚nsul del Imperio Alemâ”śĂ­n y de la Repâ”śâ•‘blica de Alemania, junto a su nieta Marâ”śÂˇa Rosario ("Charito") Freudenthal Royo posando con dos perrillos en los jardines de su "hotelito" sito en la calle de Pamplona nâ”¬â•‘ 5 (actual de Joaquâ”śÂˇn Orâ”śâ•‘s), barrio de La Romareda.', 1937, 1937, 1937, 'Anos 30', 'DELICIAS', 41.65055700, -0.89585700, '0101000020E6100000C5909C4CDCAAECBF8997A77345D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51780064118.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51780064118.webp', 'https://www.flickr.com/photos/zaragozaantigua/51780064118/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25871, 'Calle Tarragona 2013', 'Entrada al local del nâ”śâ•‘mero 14 de la calle de Tarragona, que fuera ocupado por el cine Salamanca, cuyo voladizo se conserva. Al fondo, la calle de Salamanca.', 2013, 2013, 2013, 'Siglo XXI', 'DELICIAS', 41.64835300, -0.89569900, '0101000020E6100000BCEA01F390A9ECBFBAA1293BFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54388763531.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54388763531.webp', 'https://www.flickr.com/photos/zaragozaantigua/54388763531/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26061, 'Barrio de Cariâ”śâ–’ena c.1925', 'Imagen capturada desde la altura de las antiguas naves de carpinterâ”śÂˇa y general de montaje de los Talleres de Carde y Escoriaza, con una interesante vista panorâ”śĂ­mica del que fuera original Barrio de Cariâ”śâ–’ena o de la Romareda. En primer tâ”śÂ®rmino, naves de los talleres de herrerâ”śÂˇa y montaje, y oficinas de la referida empresa, denominada Material Mâ”śâ”‚vil y Construcciones desde 1920. Detrâ”śĂ­s, el singular barrio de Cariâ”śâ–’ena, con las traseras de las viviendas unifamiliares vertebradas por el cruce de las calles de San Pedro y de Pamplona, y el murete perimetral del mar de vâ”śÂˇas la estaciâ”śâ”‚n de ferrocarril de Campo Sepulcro. A la derecha, torrecillas de la que fuera fâ”śĂ­brica de chocolares de Orâ”śâ•‘s, y algo mâ”śĂ­s hacia la derecha, fachada principal de la interesante Casa de Convalecientes. Las chimeneas del centro de la imagen corresponden con el gran complejo fabril de Talleres Mercier. Al fondo, poderoso torreâ”śâ”‚n cuadrangular de la Facultad de Medicina y Ciencias; hacia la izquierda, rotunda presencia del convento-colegio de las madres Adoratrices Esclavas del Santâ”śÂˇsimo y de la Caridad, en la calle de Hernâ”śĂ­n Cortâ”śÂ®s esquinero con la calle de la Venerable Madre Sacramento. Cierran la panorâ”śĂ­mica, mâ”śĂ­s a la izquierda, las emergentes torrecillas de la iglesia parroquial de Santa Engracia.', 1925, 1925, 1925, 'Anos 20', 'DELICIAS', 41.65034000, -0.89605000, '0101000020E6100000EA95B20C71ACECBFECA353573ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48997388177.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48997388177.webp', 'https://www.flickr.com/photos/zaragozaantigua/48997388177/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22149, 'Av. de Navarra 1958', 'Imagen capturada en la antigua carretera de Logroâ”śâ–’o, redenominada avenida de Navarra, y centrada en la tranviaria unidad nâ”¬â•‘ 160 dirigiâ”śÂ®ndose al final de la lâ”śÂˇnea 16 &quot;Portazgo de San Lamberto&quot;, cuyo tendido estaba trazado en el lado de los impares de la avenida. Este &quot;Topolino&quot; serâ”śÂˇa desguazado en 1972. El disperso entorno edilicio de la â”śÂ®poca posiblemente sea el de las inmediaciones a la calle del Arzobispo Soldevila (a la derecha, fuera de plano). Fuente visual: Josâ”śÂ® Marâ”śÂˇa Valero Suâ”śĂ­rez, Centenario del tranvâ”śÂˇa elâ”śÂ®ctrico. Zaragoza, 1902-2002.', 1958, 1958, 1958, 'Anos 50', 'DELICIAS', 41.65502400, -0.90353800, '0101000020E6100000162F1686C8E9ECBF2C0C91D3D7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27481278687.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27481278687.webp', 'https://www.flickr.com/photos/zaragozaantigua/27481278687/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22152, 'Av. de Navarra 1959', 'Vista aâ”śÂ®rea de la avenida de Navarra y su entorno. Al fondo, el râ”śÂˇo Ebro y el barrio de La Almozara. En el centro, la Estaciâ”śâ”‚n de Caminreal y las naves de Transportes Ochoa. A la derecha, el Cuartel de Ferrocarriles y el Mercado de Pescados. Abajo, el Castillo Palomar. Fuente visual: Arxiu Nacional de Catalunya.', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.65734400, -0.91386200, '0101000020E610000030D461855B3EEDBF651C23D923D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28323489712.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28323489712.webp', 'https://www.flickr.com/photos/zaragozaantigua/28323489712/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22160, 'Avenida de Navarra 1959', 'Vista aâ”śÂ®rea de la avenida de Navarra y su entorno, con el edificio circular del Mercado de Pescados en el centro. A la derecha, estaciâ”śâ”‚n de Caminreal. Fuente: TAF Helicâ”śâ–“pters. Arxiu Nacional de Catalunya.', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.65598800, -0.90651300, '0101000020E61000005DC30C8D2702EDBFC3482F6AF7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30549378343.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30549378343.webp', 'https://www.flickr.com/photos/zaragozaantigua/30549378343/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22233, 'Avenida de Madrid c.1955', 'Imagen capturada en el arranque de la calle de Ramâ”śâ”‚n de Campoamor, esquina con la avenida de Madrid, y centrada en la composiciâ”śâ”‚n tranviaria formada por el coche nâ”¬â•‘ 65 (antiguo nâ”¬â•‘ 72 transformado) y el remolque nâ”¬â•‘ 89, en servicio en la lâ”śÂˇnea 5. Torrero-Delicias, a punto de girar hacia nuestra izquierda para curvear la calle de Campoamor e incorporarse luego nuevamente a la avenida de Madrid, donde la plaza de Huesca, para retomar el trayecto de esta lâ”śÂˇnea de vuelta hasta Torrero. A la derecha de la imagen, la composiciâ”śâ”‚n coche nâ”¬â•‘ 82 + remolque nâ”¬â•‘ 78 (posiblemente), en servicio en la misma lâ”śÂˇnea, encaminados hacia Torrero. Tras ellos, el inmueble del nâ”¬â•‘ 165 de la avenida de Madrid, inmediato al arranque de la calle de Las Delicias, y gran solar donde pocos aâ”śâ–’os despuâ”śÂ®s se construirâ”śÂˇa el inmueble del nâ”¬â•‘ 161-163 de la avenida, esquinero con la calle de Don Pedro de Luna.', 1955, 1955, 1955, 'Anos 50', 'DELICIAS', 41.65312200, -0.90600700, '0101000020E61000006A4E5E6402FEECBF29266F8099D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50173250413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50173250413.webp', 'https://www.flickr.com/photos/zaragozaantigua/50173250413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22324, 'Avenida de Madrid 1969', 'Imagen de la composiciâ”śâ”‚n motor-remolque 109+109 de la lâ”śÂˇnea 5 del tranvâ”śÂˇa "Venecia-Delicias" en la Avenida de Madrid, a punto de llegar a la plaza de Huesca (hasta 1962, plaza de Rocasolano). A la derecha, se abre la calle de Nâ”¬Â¬ Sâ”¬Â¬ de Bonaria. A la izquierda, un poco mâ”śĂ­s adelante, la calle D. Pedro de Luna. Los edificios que aparecen en la imagen han sufrido una curiosa inversiâ”śâ”‚n: los mâ”śĂ­s altos, hoy son como miniaturas, comparados con los gigantes que han surgido sobre las ruinas de las parcelas que parecen mâ”śĂ­s desvalidas. Esta lâ”śÂˇnea tranviaria, dos aâ”śâ–’os despuâ”śÂ®s, serâ”śÂˇa clausurada. Fuente visual: Archivo Municipal. Gerardo Sancho. 1969', 1969, 1969, 1969, 'Anos 60', 'DELICIAS', 41.65337800, -0.90512700, '0101000020E61000003E40F7E5CCF6ECBF83F6EAE3A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16089084439.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16089084439.webp', 'https://www.flickr.com/photos/zaragozaantigua/16089084439/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22459, 'Los Sâ”śÂˇrex 1968', 'Participantes en un partido de fâ”śâ•‘tbol amistoso celebrado en 1968 en el campo de fâ”śâ•‘tbol de la estaciâ”śâ”‚n de Caminreal, en Las Delicias (al fondo). Los equipos enfrentados estaban formados por un combinado de hostelerâ”śÂˇa y por empleados del Gran Hotel. Entre los fotografiados posan los componentes del grupo musical Los Sâ”śÂˇrex. Como madrina de la ceremonia, en el centro, Elba Montalvo, cantante del grupo cubano Los Rivero. Algunos de los que aparecen en la imagen son destacados hosteleros de Zaragoza. Fuente: Heraldo de Aragâ”śâ”‚n.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65713200, -0.90927300, '0101000020E61000008A58C4B0C318EDBFD993C0E61CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31909037883.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31909037883.webp', 'https://www.flickr.com/photos/zaragozaantigua/31909037883/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22507, 'Colonia Tudor 1962', 'Imagen de la Colonia Tudor finalmente realizada en empinado terreno entre la avenida de Navarra y el castillo Palomar, que queda detrâ”śĂ­s. El proyecto original, de 1942, era mucho mâ”śĂ­s ambicioso y constaba de viviendas de varios tipos para capataces y empleados y para obreros, aunque no fue llevado a cabo. Este proyecto sâ”śÂˇ desarrollado veinte aâ”śâ–’os despuâ”śÂ®s constaba de los cinco bloques que aparecen en la fotografâ”śÂˇa. En los aâ”śâ–’os noventa estas viviendas fueron derribadas y la zona reurbanizada.', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65582300, -0.91480400, '0101000020E6100000DEFFC7091346EDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50874022983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50874022983.webp', 'https://www.flickr.com/photos/zaragozaantigua/50874022983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22520, 'Colonia Tudor 1962', 'Imagen de la Colonia Tudor ubicada en empinado terreno entre la avenida de Navarra y el castillo Palomar, que queda justo detrâ”śĂ­s. El proyecto original, de 1942, era mucho mâ”śĂ­s ambicioso y constaba de viviendas de varios tipos para capataces, empleados y obreros de esta empresa, aunque no fue llevado a cabo. El proyecto finalmente desarrollado veinte aâ”śâ–’os despuâ”śÂ®s constaba de sâ”śâ”‚lo cinco bloques. Treinta aâ”śâ–’os despuâ”śÂ®s esta colonia fue derribada y la zona reurbanizada.', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65582300, -0.91480400, '0101000020E6100000DEFFC7091346EDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54139500585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54139500585.webp', 'https://www.flickr.com/photos/zaragozaantigua/54139500585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22615, 'Av. de Madrid 1976', 'Imagen de los antiguos edificios que esquinaban la Avenida de Madrid con la calle Delicias, luego derribados para levantar otros mâ”śĂ­s higiâ”śÂ®nicos, modernos y altos. A la izquierda extrema, el nâ”¬â•‘ 4 de la calle Delicias (1969). A partir de ahâ”śÂˇ, y hasta el bloque del nâ”¬â•‘ 173 de la Av. de Madrid (1970), a la derecha extrema, todos los edificios han desaparecido, llevâ”śĂ­ndose con ellos sus bajos comerciales, como la panaderâ”śÂˇa "ARPAN" (Delicias nâ”¬â•‘ 2), la "Ferreterâ”śÂˇa Marqueta", y "Modas Yoana" (Av. Madrid nâ”¬â•‘ 167), unos Gâ”śÂ®neros de Punto, y otro despacho de "Pan y Reposterâ”śÂˇa" (Av. Madrid nâ”¬â•‘ 169), y una oficina de la Caja de Ahorros (Av. Madrid nâ”¬â•‘ 171). Sâ”śâ”‚lo sobrevive, modernizada, la agencia de la caja-banco, que se ha expandido, como el universo, y ocupa casi todo el espacio de los locales. Quâ”śÂ® cosas. Fuente: Archivo Pâ”śâ•‘blico Municipal, Gerardo Sancho Ramo.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.65294600, -0.90614600, '0101000020E6100000C3D66CE525FFECBFEA060ABC93D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19202659722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19202659722.webp', 'https://www.flickr.com/photos/zaragozaantigua/19202659722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22650, 'Calle Don Pedro de Luna c.1975', 'Calle de Don Pedro de Luna, en el barrio de Las Delicias de Zaragoza, vista desde la avenida de Madrid. Fuente: www.facebook.com/photo.php?fbid=853713991317894&set=g...', 1975, 1975, 1975, 'Anos 70', 'DELICIAS', 41.65322600, -0.90548100, '0101000020E6100000B0C7444AB3F9ECBFCD72D9E89CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21086358078.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21086358078.webp', 'https://www.flickr.com/photos/zaragozaantigua/21086358078/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22672, 'Calle del Requetâ”śÂ® Navarro 1979', 'Calle del Requetâ”śÂ® Navarro, desde 1979 de Rioja, en una vista de su arranque desde la avenida de Madrid. Centra la imagen el edificio de la Casa del Barrio, antigua fâ”śĂ­brica de galletas que en los aâ”śâ–’os 50 fuera Patâ”śÂˇn Baile, en el nâ”¬â•‘ 219-219 dupdo. de la avenida, luego derribado. Detrâ”śĂ­s, la calle de Croacia, moderno vial que marcaba tendencia respecto a la traza viaria por venir. A la izquierda, edificio de la Compaâ”śâ–’â”śÂˇa Telefâ”śâ”‚nica construido en 1972.', 1979, 1979, 1979, 'Anos 70', 'DELICIAS', 41.65221500, -0.91038500, '0101000020E6100000529B38B9DF21EDBFF67AF7C77BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24173708189.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24173708189.webp', 'https://www.flickr.com/photos/zaragozaantigua/24173708189/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22716, 'Avenida de Madrid, 1974', 'En 1902 fueron abiertas la "Escuelas Nacionales del Castillo", como primer colegio de niâ”śâ–’as y niâ”śâ–’os del que habrâ”śÂˇa de ser barrio de Delicias, en la entonces carretera de Madrid a Francia, luego avenida de Delicias. En 1935 los escolares fueron reubicados en los nuevos centros construidos durante la Segunda Repâ”śâ•‘blica, y el edificio fue reutilizado como estafeta de correos. A partir de 1939 recuperâ”śâ”‚ sus funciones como colegio, y en 1945 fue redenominado "Escuela Nacional Emilio Moreno Calvete", hasta mediados los aâ”śâ–’os 70. En la dâ”śÂ®cada de los 90, en un nuevo edificio sobre el solar del antiguo derribado fue inaugurado el actual "CEIP Emilio Moreno Calvete". En la imagen, captura del antiguo edificio colegial, sito en el nâ”¬â•‘ 145 de la avenida de Madrid. A su derecha, inmediato, quedaba el antiguo Cine Espaâ”śâ–’a, luego Delicias. Fuente visual: Foto Pilar Borobio, incluida en la exposiciâ”śâ”‚n "Escuelas y escolares en Delicias, 1900-2000", Centro Câ”śÂˇvico Esquinas del Psiquiâ”śĂ­trico.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65346100, -0.90415000, '0101000020E610000074B515FBCBEEECBF111B2C9CA4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29931566602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29931566602.webp', 'https://www.flickr.com/photos/zaragozaantigua/29931566602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22821, 'Monsalud 1974', 'Inâ”śÂ®dita imagen capturada desde la altura de uno de los modernos bloques de viviendas de la calle "E" (desde 1978 calle de Ramâ”śâ”‚n J. Sender) del polâ”śÂˇgono 40 Monsalud y centrada en las reciâ”śÂ®n inauguradas instalaciones de â”śĂĽgreda Automâ”śâ”‚vil en esta perifâ”śÂ®rica zona entre la Vâ”śÂˇa de la Hispanidad y la avenida de Navarra. Centra la escena el gran garaje-aparcamiento para un centenar de autobuses, ademâ”śĂ­s de un concesionario para exposiciâ”śâ”‚n y venta de vehâ”śÂˇculos Mercedes Benz y DKW. Fue diseâ”śâ–’ado por el arquitecto Josâ”śÂ® Beltrâ”śĂ­n Navarro, y a la inauguraciâ”śâ”‚n con bendiciâ”śâ”‚n previa asistieron Moisâ”śÂ®s Calvo Pardo, presidente-gerente de la empresa, y Mariano Horno Liria, alcalde. Al fondo y a la izquierda, bloques en construcciâ”śâ”‚n en el entorno de la calle "G" del polâ”śÂˇgono (actual nâ”¬â•‘ 3 de la calle de Biarritz), y al otro lado de la avenida de Navarra las instalaciones de la Tudor.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65665700, -0.91886000, '0101000020E61000002C4833164D67EDBF41D829560DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51633883347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51633883347.webp', 'https://www.flickr.com/photos/zaragozaantigua/51633883347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22831, 'Vâ”śÂˇa Universitas 1985', 'La ciudad va creciendo y devorando su pasado. En el cruce de la avenida Madrid con vâ”śÂˇa Universitas (edificio de Telefâ”śâ”‚nica en primer plano a la izquierda) aâ”śâ•‘n quedaban algunas casas con corral. Pero ya no.', 1985, 1985, 1985, 'Anos 80', 'DELICIAS', 41.65199200, -0.91013700, '0101000020E61000004A253CA1D71FEDBF77A04E7974D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14701998757.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14701998757.webp', 'https://www.flickr.com/photos/zaragozaantigua/14701998757/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22834, 'Cuartel Las Delicias c.1987', 'Acuartelamiento ferroviario Las Delicias, en la avenida de Navarra. Ocupado por la Compaâ”śâ–’â”śÂˇa de Ferrocarriles, fue derribado en 2004.', 1987, 1987, 1987, 'Anos 80', 'DELICIAS', 41.65564900, -0.90749600, '0101000020E6100000AF06280D350AEDBFDA53724EECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14754547999.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14754547999.webp', 'https://www.flickr.com/photos/zaragozaantigua/14754547999/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23056, 'Calle del Capitâ”śĂ­n Pina 1994', 'Imagen capturada en el tramo del paseo de Calanda delimitado por las transversales calles de Graus y de Bolivia, y centrado en el cartel anunciador de la construcciâ”śâ”‚n de un garaje subterrâ”śĂ­neo que conservarâ”śÂˇa la denominaciâ”śâ”‚n franquista de este vial (calle del Capitâ”śĂ­n Pina, antes calle Pinos) cuyo ancho aspecto era resultado del previo derribo de las parcelas occidentales de esta calle. Este proyecto de ensanchamiento ya habâ”śÂˇa sido perfilado (entre la avenida de Madrid y la calle de Domingo Ram) en un Plan Especial aprobado en 1973 que no tuvo desarrollo posterior. De resultas de esta intervenciâ”śâ”‚n, el paseo se extiende actualmente desde la avenida de Navarra y hasta la calle de la Duquesa de Villahermosa.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65156700, -0.90362500, '0101000020E6100000D122DBF97EEAECBF9013268C66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50449704672.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50449704672.webp', 'https://www.flickr.com/photos/zaragozaantigua/50449704672/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23140, 'Barrio del AVE 2006', 'Avance del proyecto de urbanizaciâ”śâ”‚n del nuevo barrio del AVE, presentado en mayo de 2006 y diseâ”śâ–’ado por el arquitecto Eduardo Leira. Segâ”śâ•‘n â”śÂ®l, el paseo de la Estaciâ”śâ”‚n serâ”śÂˇa "el nuevo paseo de la Independencia". La plaza de la Estaciâ”śâ”‚n (luego denominada de El Periâ”śâ”‚dico de Aragâ”śâ”‚n) serâ”śÂˇa como "el Rockefeller Center de Nueva York". El presidente de Aragâ”śâ”‚n, Marcelino Iglesias, considerâ”śâ”‚ que era "el mayor impulso nunca dado a esta ciudad". De las nuevas edificaciones, mostradas en color marrâ”śâ”‚n, la â”śâ•‘nica realizada en 2017 es el Centro de Especialidades Inocencio Jimâ”śÂ®nez del Servicio Aragonâ”śÂ®s de Salud, en la avenida de Navarra 78, inaugurado en febrero de 2015. Fuente: Heraldo de Aragâ”śâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'DELICIAS', 41.66025800, -0.91682600, '0101000020E61000007DEBC37AA356EDBF10768A5583D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31830351741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31830351741.webp', 'https://www.flickr.com/photos/zaragozaantigua/31830351741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23189, 'Plaza de Huesca 2010', 'Foto Pedro Zapater Delgado, 2010. Surtidor de gasâ”śâ”‚leo en estado de abandono, situado en la plaza de Huesca de Zaragoza hasta su retirada en 2014. Fue instalado en 1960 y dejâ”śâ”‚ de prestar servicio dos dâ”śÂ®cadas despuâ”śÂ®s. Fuente: www.heraldo.es/noticias/zaragoza/un_surtidor_olvidado_las...', 2010, 2010, 2010, 'Siglo XXI', 'DELICIAS', 41.65315300, -0.90630800, '0101000020E6100000274D83A27900EDBF64247B849AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19244621146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19244621146.webp', 'https://www.flickr.com/photos/zaragozaantigua/19244621146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23436, 'Castillo de Palomar 1960', 'Finca con casa de campo en forma de castillo, estaba situada en la actual finca del Parque del Castillo Palomar en el barrio de Delicias y estuvo en propiedad privada y en pie hasta la dâ”śÂ®cada de los aâ”śâ–’os 60, aunque sus ruinas y cimientos se pudieron contemplar hasta que toda aquella zona y ya siendo propiedad municipal se convirtiâ”śâ”‚ en parque. Fuente : eszaragoza.blogspot.com.es/', 1960, 1960, 1960, 'Anos 60', 'DELICIAS', 41.65582300, -0.91205700, '0101000020E6100000D9CF6229922FEDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700702280.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700702280.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700702280/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23443, 'Castillo de Palomar c.1955', '"Colegio Rosa Arjâ”śâ”‚. Clase de Gimnasia en el Castillo Palomar". Este Colegio Pâ”śâ•‘blico estaba en la calle San Antonio Abad, y para ir al patio recorrâ”śÂˇan medio kilâ”śâ”‚metro hasta llegar al entorno del "Castillo Palomar", una finca de la familia Palomar en la que se habâ”śÂˇan regalado una casa con apariencia de castillo, en una propiedad que llegaba desde la Avenida de Navarra hasta la Carretera de los Enlaces. Imagen de niâ”śâ–’as jugando, con el Castillo Palomar de fondo, tras los pinos. En la actualidad aquâ”śÂˇ hay un parque pâ”śâ•‘blico de algo mâ”śĂ­s de 55 Ha. de extensiâ”śâ”‚n, y todo un nuevo barrio: Monsalud.', 1955, 1955, 1955, 'Anos 50', 'DELICIAS', 41.65582300, -0.91205700, '0101000020E6100000D9CF6229922FEDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14945922706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14945922706.webp', 'https://www.flickr.com/photos/zaragozaantigua/14945922706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23469, 'Castillo de Palomar c.1929', 'Imagen de la que fuera original casa de Narciso Palomar y Cebriâ”śĂ­n y de Rafaela Mendâ”śÂˇvil y Fâ”śâ•‘rida construida entre 1882 y 1920 en el alto de Monsalud dominando una enorme finca que en el momento de realizar esta fotografâ”śÂˇa era propiedad de Eustoquia Caballero y Castillejo. A pesar de que Narciso Palomar falleciâ”śâ”‚ en 1885 y no vio terminada la gran casa, â”śÂ®sta conservarâ”śÂˇa su nombre desde entonces, llegando esa denominaciâ”śâ”‚n hasta nuestros dâ”śÂˇas. La captura ha sido realizada desde el sur de la enorme propiedad, junto al ascendente camino hasta la gran casa construida en bizarras formas historicistas y mudâ”śÂ®jares sobre un alto que se elevaba casi cien metros respecto de su entorno, visible por ello desde mucha distancia, tal que los antiguos castillos medievales. Al fondo sobresalen los montes de Juslibol por encima de los muros perimetrales del recinto. Fuente visual: Colecciâ”śâ”‚n Josâ”śÂ® Luis Cintora.', 1929, 1929, 1929, 'Anos 20', 'DELICIAS', 41.65582300, -0.91205700, '0101000020E6100000D9CF6229922FEDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30997518928.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30997518928.webp', 'https://www.flickr.com/photos/zaragozaantigua/30997518928/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23477, 'Castillo de Palomar 1943', 'Imagen capturada en el entorno del Castillo Palomar, en la periferia del barrio de Delicias-Terminillo, frente a la estaciâ”śâ”‚n de ferrocarril de Caminreal, a la cota 223.5. La fachada principal de ingreso al castillo hace de telâ”śâ”‚n de fondo a un invernal posado donde destaca un sargento, luciendo el caracterâ”śÂˇstico capote castrense de la â”śÂ®poca. Fuente visual: www.todocoleccion.net/', 1943, 1943, 1943, 'Anos 40', 'DELICIAS', 41.65582300, -0.91205700, '0101000020E6100000D9CF6229922FEDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33602265582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33602265582.webp', 'https://www.flickr.com/photos/zaragozaantigua/33602265582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23695, 'Cooperativa de San Antonio 1914', 'La primera cooperativa de casas baratas de Zaragoza fue la "Cooperativa de San Antonio" (abril 1913), para la que el arquitecto Teodoro Râ”śÂˇos proyectâ”śâ”‚ 40 viviendas unifamiliares en las inmediaciones de la carretera de Navarra. Estas casas se destinaban a obreros y empleados de poco sueldo, que pagarâ”śÂˇan mensualidades hasta convertirse en propietarios de la casa. En 1917 se hizo una ampliaciâ”śâ”‚n que llegarâ”śÂˇa hasta la carretera de Madrid por la calle del Arzobispo (luego, Arzobispo Soldevila). En la imagen, vial central en torno al que se ordenaban las Casas Baratas. Cada dos ventanas, una casa (piso superior, dos habitaciones; piso inferior, patio, "water-closset", comedor, cocina, cuarto amplio). Al fondo, la carretera de Navarra, o de Logroâ”śâ–’o. Fuente visual: www.facebook.com/photo.php?fbid=855742017781758&set=g... Fuente textual: Marâ”śÂˇa Pilar Biel Ibâ”śĂ­â”śâ–’ez, Zaragoza y la industrializaciâ”śâ”‚n: la arquitectura industrial en la capital aragonesa entre 1875-1936, IFC, 2004', 1914, 1914, 1914, 'Anos 10', 'DELICIAS', 41.65466900, -0.90383500, '0101000020E6100000795DBF6037ECECBF3E5A9C31CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15380674223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15380674223.webp', 'https://www.flickr.com/photos/zaragozaantigua/15380674223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23701, 'Calle de Antonio Fleta 1964', 'De todas las abundantes acequias que como una red se extendâ”śÂˇan por Zaragoza, esta imagen nos lleva al barrio de Delicias, al cruce de la calle Antonio Fleta (antes, de Miguel Fleta), con la de Nâ”¬Â¬ Sâ”¬Â¬ de Bonaria (por donde circula el camiâ”śâ”‚n), desde la que una acequia bajaba por toda la calle San Antonio Abad, la cruzaba medio al aire, y luego se bifuncaba, yendo un riego hasta la plaza de Huesca, y otra seguâ”śÂˇa en paralelo a la antigua carretera de Madrid durante un buen tramo. Esta imagen de las acequias al aire era recurrente en la Zaragoza de la periferia. Fotografâ”śÂˇa datada gracias a la amable aportaciâ”śâ”‚n de Fernando Benito. Fuente visual: Archivo Municipal, Gerardo Sancho Ramo, 1964.', 1964, 1964, 1964, 'Anos 60', 'DELICIAS', 41.65400400, -0.90515900, '0101000020E610000016C3D50110F7ECBF02BA2F67B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18194641035.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18194641035.webp', 'https://www.flickr.com/photos/zaragozaantigua/18194641035/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23703, 'Plaza de Huesca 1980', 'La antigua plaza de Gregorio Rocasolano contaba desde 1960 con un surtidor de gasâ”śâ”‚leo que aparece en la foto. Fue desmontado en 2014. Fuente: Zaragoza barrio a barrio, 1981.', 1980, 1980, 1980, 'Anos 80', 'DELICIAS', 41.65315300, -0.90630800, '0101000020E6100000274D83A27900EDBF64247B849AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18649882333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18649882333.webp', 'https://www.flickr.com/photos/zaragozaantigua/18649882333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23706, 'Calle de Graus 1978', 'Aspecto de la cuesta de la calle de Graus del barrio de Las Delicias, con la calle de Don Pedro de Luna a la espalda y la del Doctor Pâ”śÂ®rez Serrano al fondo. A la derecha, bares desaparecidos, como El Pinar, câ”śÂ®lebre por sus patatas bravas. Fuente: www.rafaelcastillejo.com', 1978, 1978, 1978, 'Anos 70', 'DELICIAS', 41.65189400, -0.90481700, '0101000020E6100000B4ACFBC742F4ECBFB43A394371D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21109557458.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21109557458.webp', 'https://www.flickr.com/photos/zaragozaantigua/21109557458/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23716, 'Calle de Ramâ”śâ”‚n de Campoamor c.1962', 'Vista de la calle de Ramâ”śâ”‚n de Campoamor desde la avenida de Madrid, con un tranvâ”śÂˇa de la lâ”śÂˇnea 5 "Venecia-Delicias". El edificio de la derecha perdura en 2016; no asâ”śÂˇ el puesto de venta de cupones. Fuente visual: foto Christian Schnabel, en historiastren.blogspot.com', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65297600, -0.90697300, '0101000020E61000003A5CAB3DEC05EDBF5589B2B794D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27584992994.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27584992994.webp', 'https://www.flickr.com/photos/zaragozaantigua/27584992994/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23720, 'Av. de Madrid 1964', 'Imagen de la avenida de Madrid, a la altura de la reciente calle denominada Garcilaso de la Vega (izquierda), cuando dos unidades de la serie 40 (nâ”¬â•‘ 44, y nâ”¬â•‘ 47) en servicio en la lâ”śÂˇnea 14 (Oliver), se estâ”śĂ­n cruzando en el desvâ”śÂˇo de mitad de trayecto, entre la plaza de Huesca (antigua de Rocasolano, al fondo de la imagen), y el Enlace de Carreteras. Era curiosa la denominaciâ”śâ”‚n de esta lâ”śÂˇnea, porque durante casi veinte aâ”śâ–’os dio servicio al barrio de Oliver, sin llegar a entrar en â”śÂ®l. Estas dos unidades tranviarias fueron retiradas de la circulaciâ”śâ”‚n y desguazadas al poco tiempo. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1964, 1964, 1964, 'Anos 60', 'DELICIAS', 41.65151300, -0.91285100, '0101000020E610000061DEE34C1336EDBF9DF529C764D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31500011746.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31500011746.webp', 'https://www.flickr.com/photos/zaragozaantigua/31500011746/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
